import{_ as r,c as t,o as a,ag as i}from"./chunks/framework.By5zrZ8k.js";const p=JSON.parse('{"title":"Sizing Guide","description":"","frontmatter":{},"headers":[],"relativePath":"projects/mlai/neo/core/d-sizing.md","filePath":"projects/mlai/neo/core/d-sizing.md","lastUpdated":1773130255000}'),o={name:"projects/mlai/neo/core/d-sizing.md"};function n(d,e,s,l,c,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="sizing-guide" tabindex="-1">Sizing Guide <a class="header-anchor" href="#sizing-guide" aria-label="Permalink to &quot;Sizing Guide&quot;">​</a></h1><p>NetApp Project Neo v4 is composed of four microservices (API, Worker, Extractor, NER) plus a PostgreSQL database. Resource requirements depend on the volume of files being indexed and the processing throughput needed.</p><h2 id="deployment-profiles" tabindex="-1">Deployment Profiles <a class="header-anchor" href="#deployment-profiles" aria-label="Permalink to &quot;Deployment Profiles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Profile</th><th>Files</th><th>CPU</th><th>RAM</th><th>GPU</th><th>Storage</th></tr></thead><tbody><tr><td>Small</td><td>&lt;50K</td><td>4 vCPU</td><td>8 GB</td><td>Optional</td><td>20 GB</td></tr><tr><td>Medium</td><td>50K-500K</td><td>8 vCPU</td><td>16 GB</td><td>Recommended</td><td>50 GB</td></tr><tr><td>Large</td><td>500K-2M</td><td>16 vCPU</td><td>32 GB</td><td>Recommended</td><td>100 GB</td></tr><tr><td>Enterprise</td><td>2M+</td><td>32+ vCPU</td><td>64+ GB</td><td>Required</td><td>200+ GB</td></tr></tbody></table><p>The above figures represent the total resources across all services. See the per-service breakdown below for how to distribute resources.</p><h2 id="per-service-resource-breakdown" tabindex="-1">Per-Service Resource Breakdown <a class="header-anchor" href="#per-service-resource-breakdown" aria-label="Permalink to &quot;Per-Service Resource Breakdown&quot;">​</a></h2><h3 id="api-service" tabindex="-1">API Service <a class="header-anchor" href="#api-service" aria-label="Permalink to &quot;API Service&quot;">​</a></h3><p>Lightweight HTTP service handling REST requests, authentication, and routing. Minimal resource requirements.</p><ul><li>CPU: 1-2 vCPU</li><li>RAM: 1-2 GB</li><li>GPU: Not required</li><li>I/O: Low</li></ul><h3 id="worker-service" tabindex="-1">Worker Service <a class="header-anchor" href="#worker-service" aria-label="Permalink to &quot;Worker Service&quot;">​</a></h3><p>Handles file discovery, SMB crawling, scheduling, and Microsoft Graph uploads. CPU and network intensive during crawl operations.</p><ul><li>CPU: 2-8 vCPU (scales with concurrent crawl jobs)</li><li>RAM: 2-8 GB</li><li>GPU: Not required</li><li>I/O: High network throughput (SMB + Graph API)</li></ul><h3 id="extractor-service" tabindex="-1">Extractor Service <a class="header-anchor" href="#extractor-service" aria-label="Permalink to &quot;Extractor Service&quot;">​</a></h3><p>Performs document content extraction (PDF, Office, images). Heavily benefits from GPU acceleration for OCR and document layout analysis.</p><ul><li>CPU: 2-8 vCPU</li><li>RAM: 4-16 GB</li><li>GPU: Recommended (CUDA for NVIDIA, ROCm for AMD)</li><li>I/O: Moderate</li></ul><h3 id="ner-service" tabindex="-1">NER Service <a class="header-anchor" href="#ner-service" aria-label="Permalink to &quot;NER Service&quot;">​</a></h3><p>Runs Named Entity Recognition models against extracted text. GPU-intensive for inference workloads.</p><ul><li>CPU: 2-4 vCPU</li><li>RAM: 4-8 GB</li><li>GPU: Recommended for production workloads</li><li>I/O: Low</li></ul><h3 id="postgresql-database" tabindex="-1">PostgreSQL Database <a class="header-anchor" href="#postgresql-database" aria-label="Permalink to &quot;PostgreSQL Database&quot;">​</a></h3><p>Primary data store for metadata, extracted content, search indexes, and ACLs. I/O intensive, especially during large crawl operations.</p><ul><li>CPU: 2-4 vCPU</li><li>RAM: 4-16 GB</li><li>GPU: Not required</li><li>I/O: High (SSD strongly recommended)</li></ul><h2 id="database-sizing" tabindex="-1">Database Sizing <a class="header-anchor" href="#database-sizing" aria-label="Permalink to &quot;Database Sizing&quot;">​</a></h2><p>The database requirements depend on the size of your source data and the number of indexed documents:</p><ul><li><strong>General rule</strong>: ~2 GB of database storage per 100 GB of source documents indexed (approximately 2% of source data size)</li><li><strong>With full-text content storage</strong>: Database size may increase to 5-10% of source data size</li><li><strong>NER results</strong>: Add approximately 10-20% to the base database size if NER is enabled</li></ul><p>Ensure your PostgreSQL instance has adequate disk I/O performance. SSDs are strongly recommended for production deployments.</p><h2 id="gpu-variants" tabindex="-1">GPU Variants <a class="header-anchor" href="#gpu-variants" aria-label="Permalink to &quot;GPU Variants&quot;">​</a></h2><p>Neo provides GPU-accelerated container variants for the Extractor and NER services:</p><ul><li><strong>CUDA</strong> (NVIDIA): Images tagged with <code>-cuda</code> suffix</li><li><strong>ROCm</strong> (AMD): Images tagged with <code>-rocm</code> suffix</li></ul><p>GPU acceleration significantly improves extraction and NER throughput. For deployments processing more than 50K files, GPU is recommended. For Enterprise deployments, GPU is required for acceptable processing times.</p><h2 id="performance-benchmarking" tabindex="-1">Performance Benchmarking <a class="header-anchor" href="#performance-benchmarking" aria-label="Permalink to &quot;Performance Benchmarking&quot;">​</a></h2><p>For detailed performance benchmarks and tuning guidance, see <a href="./m-performance.html">Performance</a>.</p>',31)])])}const m=r(o,[["render",n]]);export{p as __pageData,m as default};
